output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?bookLabel WHERE {
  wd:Q1422318 rdfs:label ?bookLabel
  FILTER(LANG(?bookLabel) = 'en')
}

args.sparql:
SELECT ?book ?bookLabel
WHERE {
  wd:Q280898 wdt:P161 ?book.
  ?book wdt:P1697 ?order.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}
ORDER BY ?order
LIMIT 1

SELECT ?book ?bookLabel
WHERE {
  ?book wdt:P155 wd:Q280898.
  ?book wdt:P1697 ?order.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}
ORDER BY ?order
LIMIT 1

SELECT ?bookLabel
WHERE {
  ?book wdt:P155 wd:Q280898.
  ?book p:P155/ps:P1697 ?order.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}
ORDER BY ?order
LIMIT 1

SELECT ?book ?bookLabel
WHERE {
  ?book p:P155 ?statement.
  ?statement ps:P155 wd:Q280898.
  ?statement pq:P1697 ?order.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}
ORDER BY ?order
LIMIT 1
